CREATE TRIGGER [dbo].[InventoryItemScrap_History]ON [dbo].[InventoryItemScrap]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.InventoryItemScrapId IS NOT NULL AND d.InventoryItemScrapId IS NULL THEN 'I' 		WHEN i.InventoryItemScrapId IS NOT NULL AND d.InventoryItemScrapId IS NOT NULL THEN 'U' 		WHEN i.InventoryItemScrapId IS NULL AND d.InventoryItemScrapId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.InventoryItemScrapId = d.InventoryItemScrapId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_InventoryItemScrap([InventoryItemScrapId], [InventoryItemId], [DefectId], [UserId], [Quantity], [Comment], [ScrapDate], [ScrapDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [InventoryItemScrapId], [InventoryItemId], [DefectId], [UserId], [Quantity], [Comment], [ScrapDate], [ScrapDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_InventoryItemScrap([InventoryItemScrapId], [InventoryItemId], [DefectId], [UserId], [Quantity], [Comment], [ScrapDate], [ScrapDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [InventoryItemScrapId], [InventoryItemId], [DefectId], [UserId], [Quantity], [Comment], [ScrapDate], [ScrapDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND